function solve(m: number, n: number, waitCost: number[][]): number {
    // Create a DP table where dp[i][j][k] represents the minimal cost to reach (i,j) at step k
    // Since the grid is m x n and the maximum steps could be up to (m + n) * 2, we need to track steps
    // However, tracking all steps is impractical for large m and n, so we optimize by tracking parity (odd/even step)

    // Initialize DP table with Infinity
    const dp: number[][][] = new Array(m);
    for (let i = 0; i < m; i++) {
        dp[i] = new Array(n);
        for (let j = 0; j < n; j++) {
            dp[i][j] = new Array(2).fill(Infinity);
        }
    }

    // Starting point (0,0) at step 1 (odd step)
    dp[0][0][1] = (0 + 1) * (0 + 1); // entry cost

    // Directions for movement: right (0,1) and down (1,0)
    const directions = [[0, 1], [1, 0]];

    // We need to process cells in BFS manner, tracking the step count
    // Using a queue where each element is [i, j, step]
    const queue: [number, number, number][] = [];
    queue.push([0, 0, 1]);

    while (queue.length > 0) {
        const [i, j, step] = queue.shift()!;
        const currentCost = dp[i][j][step % 2];

        if (i === m - 1 && j === n - 1) {
            continue; // already at target, no need to process further
        }

        if (step % 2 === 1) {
            // Odd step: move right or down
            for (const [di, dj] of directions) {
                const ni = i + di;
                const nj = j + dj;
                if (ni < m && nj < n) {
                    const nextStep = step + 1;
                    const moveCost = (ni + 1) * (nj + 1);
                    const totalCost = currentCost + moveCost;
                    if (totalCost < dp[ni][nj][nextStep % 2]) {
                        dp[ni][nj][nextStep % 2] = totalCost;
                        queue.push([ni, nj, nextStep]);
                    }
                }
            }
        } else {
            // Even step: wait
            const nextStep = step + 1;
            const waitCostHere = waitCost[i][j];
            const totalCost = currentCost + waitCostHere;
            if (totalCost < dp[i][j][nextStep % 2]) {
                dp[i][j][nextStep % 2] = totalCost;
                queue.push([i, j, nextStep]);
            }
        }
    }

    // The answer is the minimal cost to reach (m-1, n-1) at any step
    return Math.min(dp[m-1][n-1][0], dp[m-1][n-1][1]);
}
